import React, { useState } from "react";
import { Row, Col } from "react-bootstrap";
import Button from "react-bootstrap/Button";
import { AiOutlineDownload } from "react-icons/ai";
import { Document, Page, pdfjs } from "react-pdf";
import "react-pdf/dist/esm/Page/AnnotationLayer.css";
import Slideshow from "./Slideshow";
import { BsBoxArrowUpRight } from "react-icons/bs";

import splinterExcel from "../../../Assets/Robotics/SplinterCablesConnectorsIOs.pdf";
import splinterDoc from "../../../Assets/Robotics/SplinterToolheads.pdf";
import { SLIDES, HIGHLIGHTS, CONTENT } from "../../../data/splinter";

pdfjs.GlobalWorkerOptions.workerSrc = `//cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjs.version}/pdf.worker.min.js`;

const bodyStyle = {
    color: "var(--text)",
    fontFamily: "Lato, sans-serif",
    lineHeight: "1.9",
    fontSize: "var(--font-lg)",
    paddingLeft: "24px",
    paddingRight: "24px",
    textAlign: "left",
    textIndent: "2em",
};

function SmallPdf({ file, label, caption }) {
    const [numPages, setNumPages] = useState(null);

    return (
        <div style={{ textAlign: "center" }}>
            <h5 style={{
                color: "var(--primary)",
                fontFamily: "Nunito, sans-serif",
                marginBottom: "10px",
            }}>
                {label}
            </h5>
            <div style={{
                overflow: "auto",
                borderRadius: "8px",
                border: "1px solid rgba(155,114,207,0.3)",
                maxHeight: "360px",
                marginBottom: "10px",
            }}>
                <Document
                    file={file}
                    onLoadSuccess={({ numPages }) => setNumPages(numPages)}
                    className="d-flex flex-column align-items-center"
                >
                    {Array.from(new Array(numPages), (_, i) => (
                        <Page key={i + 1} pageNumber={i + 1} scale={0.5} />
                    ))}
                </Document>
            </div>
            <p style={{
                color: "rgba(255,255,255,0.55)",
                fontFamily: "Lato, sans-serif",
                fontSize: "var(--font-sm)",
                fontStyle: "italic",
                marginBottom: "10px",
            }}>
                {caption}
            </p>
            <Button variant="primary" href={file} target="_blank" size="sm">
                <AiOutlineDownload /> &nbsp;Download
            </Button>
        </div>
    );
}

function Splinter() {
    return (
        <div style={{
            border: "1px solid var(--primary)",
            borderRadius: "16px",
            boxShadow: "0 0 20px rgba(155, 114, 207, 0.2)",
            backgroundColor: "var(--background)",
            padding: "16px",
            marginBottom: "40px",
        }}>
            {/* Row 1: slideshow left, text right */}
            <Row className="align-items-center g-3" style={{ marginBottom: "24px" }}>
                <Col md={6}>
                    <Slideshow slides={SLIDES} noBorder />
                </Col>
                <Col md={6}>
                    <p style={{ ...bodyStyle, marginBottom: "16px" }}>
                        "Splinter" was one of my best friends at NBRR, he is an ABB brand 6-axis robotic arm capable of printing
                        with both thermoplastic pellets and ceramic clay — two completely different materials, two completely different
                        electrical systems, one machine. Each toolhead required its own wiring architecture spanning 120V AC, 24V DC,
                        and low-voltage signal lines across three custom connectors, all coordinated through a layered control stack:
                        ABB I/Os, solid state relays, temperature controllers, and a Teknic ClearCore running{" "}
                        <a
                            href="https://github.com/kcullen3/robotic-arm-toolhead-control"
                            target="_blank"
                            rel="noopener noreferrer"
                            style={{ color: "var(--accent1_dull)", textDecoration: "underline" }}
                        >
                            custom C++ code<BsBoxArrowUpRight size={10} />
                        </a>
                        {" "}I wrote from scratch.
                    </p>
                    <p style={{ ...bodyStyle, marginBottom: 0 }}>The real challenge wasn't any single system —
                        it was making all of them coexist without burning anything down. I had to design
                        fault-tolerant switching logic so one toolhead couldn't accidentally fry the other,
                        write two completely separate motor control scripts for two motors that had nothing
                        in common, and document all of it clearly enough that someone else could run it
                        safely. There's no template for a project like Splinter. Get something wrong and
                        you find out immediately, and it's usually expensive, and occasionally loud.
                    </p>
                </Col>
            </Row>

            <div className="robotics-highlights" style={{ marginBottom: "24px" }}>
                {HIGHLIGHTS.map((item, i) => (
                    <div key={i} className="robotics-highlight-item">
                        <span className="cyan">✦</span> {item}
                    </div>
                ))}
            </div>

            {/* Row 2: two small PDFs side by side */}
            <Row className="g-4">
                <Col md={6}>
                    <SmallPdf
                        file={splinterExcel}
                        label={CONTENT.excelLabel}
                        caption={CONTENT.excelCaption}
                    />
                </Col>
                <Col md={6}>
                    <SmallPdf
                        file={splinterDoc}
                        label={CONTENT.docLabel}
                        caption={CONTENT.docCaption}
                    />
                </Col>
            </Row>
        </div>
    );
}

export default Splinter;
